from flask import Flask, request, jsonify
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
import joblib

app = Flask(__name__)

# Load pre-trained model and vectorizer
model = joblib.load('spam_detection_model.pkl')
vectorizer = joblib.load('vectorizer.pkl')

@app.route('/predict', methods=['POST'])
def predict_spam():
    email_text = request.json.get('email_text')
    if not email_text:
        return jsonify({'error': 'Email text is required'}), 400

    # Transform the input email using the pre-trained vectorizer
    X_test = vectorizer.transform([email_text])

    # Predict spam probability
    spam_probability = model.predict_proba(X_test)[0][1]

    return jsonify({'spam_probability': spam_probability})

if __name__ == '__main__':
    app.run(debug=True)